-- Prayer Wall moderation upgrade
-- Run this AFTER supabase-schema.sql in Supabase SQL Editor.
-- Reference data is copied unchanged from better-profane-words 1.0.3.

alter table public.posts add column if not exists moderation_source text;
alter table public.posts add column if not exists moderation_severity integer check (moderation_severity between 0 and 5);
alter table public.posts add column if not exists moderation_matches jsonb not null default '[]'::jsonb;
alter table public.reports add column if not exists reporter_token text;
create unique index if not exists reports_unique_reporter_idx
  on public.reports(post_id, reporter_token)
  where reporter_token is not null;

create table if not exists public.moderation_terms (
  word text primary key,
  categories text[] not null,
  intensity integer not null check (intensity between 1 and 5),
  pattern text not null
);

alter table public.moderation_terms enable row level security;
revoke all on public.moderation_terms from anon, authenticated;

truncate table public.moderation_terms;
insert into public.moderation_terms(word, categories, intensity, pattern)
