create or replace function public.check_submission_moderation(input_body text)
returns jsonb
language sql
stable
security definer
set search_path = public
as $$
  with matches as (
    select word, categories, intensity
    from public.moderation_terms
    where lower(input_body) ~ pattern
    order by intensity desc, word
  )
  select jsonb_build_object(
    'flagged', exists(select 1 from matches),
    'severity', coalesce((select max(intensity) from matches), 0),
    'matches', coalesce(
      (select jsonb_agg(jsonb_build_object(
        'word', word,
        'categories', categories,
        'intensity', intensity
      )) from matches),
      '[]'::jsonb
    )
  );
$$;

create or replace function public.submit_post(
  submission_type public.post_type,
  submission_body text,
  submission_display_name text default null,
  submission_tag_id text default null
)
returns public.posts
language plpgsql
security definer
set search_path = public
as $$
declare
  result public.posts;
  moderation jsonb;
  is_flagged boolean;
  severity integer;
  matches jsonb;
begin
  if char_length(trim(submission_body)) not between 12 and 500 then
    raise exception 'Submission must be between 12 and 500 characters.';
  end if;

  if submission_display_name is not null and char_length(submission_display_name) > 40 then
    raise exception 'Display name must be 40 characters or fewer.';
  end if;

  moderation := public.check_submission_moderation(submission_body);
  is_flagged := coalesce((moderation->>'flagged')::boolean, false);
  severity := coalesce((moderation->>'severity')::integer, 0);
  matches := coalesce(moderation->'matches', '[]'::jsonb);

  insert into public.posts(
    type, body, display_name, status, tag_id,
    moderation_reason, moderation_source, moderation_severity, moderation_matches
  ) values (
    submission_type,
    trim(submission_body),
    nullif(trim(submission_display_name), ''),
    case when is_flagged then 'pending'::public.post_status else 'active'::public.post_status end,
    submission_tag_id,
    case when is_flagged then format('Automatic moderation matched %s reference term(s).', jsonb_array_length(matches)) else null end,
    case when is_flagged then 'automatic_dictionary' else null end,
    case when is_flagged then severity else null end,
    matches
  ) returning * into result;

  return result;
end;
$$;

create or replace function public.report_post(
  target_post_id uuid,
  source_tag_id text default null,
  source_reporter_token text default null
)
returns integer
language plpgsql
security definer
set search_path = public
as $$
declare
  new_count integer;
  inserted_id bigint;
begin
  if not exists (
    select 1 from public.posts
    where id = target_post_id and status = 'active'
  ) then
    raise exception 'Post is not active';
  end if;

  insert into public.reports(post_id, tag_id, reporter_token)
  values (target_post_id, source_tag_id, source_reporter_token)
  on conflict (post_id, reporter_token) where reporter_token is not null do nothing
  returning id into inserted_id;

  if inserted_id is null and source_reporter_token is not null then
    select report_count into new_count from public.posts where id = target_post_id;
    return new_count;
  end if;

  update public.posts
  set report_count = report_count + 1,
      status = case when report_count + 1 >= 3 then 'pending'::public.post_status else status end,
      moderation_source = case when report_count + 1 >= 3 then 'user_reports' else moderation_source end,
      moderation_severity = case when report_count + 1 >= 3 then null else moderation_severity end,
      moderation_reason = case when report_count + 1 >= 3 then 'Pulled from the public wall after 3 distinct visitor reports.' else moderation_reason end,
      updated_at = now()
  where id = target_post_id
  returning report_count into new_count;

  return new_count;
end;
$$;

revoke all on function public.report_post(uuid, text) from public;
drop function if exists public.report_post(uuid, text);
revoke all on function public.report_post(uuid, text, text) from public;
grant execute on function public.report_post(uuid, text, text) to anon, authenticated;

-- Public submissions must use submit_post so moderation cannot be bypassed.
revoke insert on public.posts from anon;
revoke insert on public.posts from authenticated;
revoke all on function public.submit_post(public.post_type, text, text, text) from public;
revoke all on function public.check_submission_moderation(text) from public;
grant execute on function public.submit_post(public.post_type, text, text, text) to anon, authenticated;

-- Keep admins able to update posts after review.
grant select on public.posts to anon, authenticated;
grant update on public.posts to authenticated;
